params.script:
// =============================================================
// 1. 入力取得
// =============================================================
var classification = "NO_RESULT";
var rawInput = $runner.getModuleResult("入力_用件確認");
var text = "";
if (rawInput && typeof rawInput === "object" && rawInput.text) {
    text = String(rawInput.text);
} else if (typeof rawInput === "string") {
    text = rawInput;
}
text = text == null ? "" : String(text).trim();


// =============================================================
// 2. 正規化
// =============================================================
function normalize(s) {
    if (!s) return "";
    var n = s;
    n = n.replace(/[\r\n\t]/g, "");
    n = n.replace(/[\uFF10-\uFF19]/g, function(c) {
        return String.fromCharCode(c.charCodeAt(0) - 0xFF10 + 0x30);
    });
    n = n.replace(/[\uFF21-\uFF3A\uFF41-\uFF5A]/g, function(c) {
        return String.fromCharCode(c.charCodeAt(0) - 0xFEE0);
    });
    n = n.replace(/[\u30A1-\u30F6]/g, function(c) {
        return String.fromCharCode(c.charCodeAt(0) - 0x60);
    });
    n = n.replace(/[\s\u3001\u3002,\.\-_\/\u30FB:;\uff01!\uff1f?\u300c\u300d\u300e\u300f\uff08\uff09()\u3000]/g, "");
    return n;
}


// =============================================================
// 3. repeat判定
// =============================================================
function hasRepeatMarker(n) {
    return (
        /(もう(いち|一)(ど|度|かい|回))/.test(n) ||
        /(もういっかい|もういっど)/.test(n) ||
        /(も(いち|一)(ど|度|かい|回))/.test(n) ||
        /(さいど(おねがい|お願い|きかせ|いって)?)/.test(n) ||
        /(再度(おねがい|お願い|きかせ|いって)?)/.test(n) ||
        /(まえ(に)?もど(って|る|して))/.test(n) ||
        /(前(に)?戻(って|る|して))/.test(n) ||
        /(きこえ(ない|ません|なかった|づらい))/.test(n) ||
        /(聞こえ(ない|ません|なかった|づらい))/.test(n) ||
        /(ききと(れない|れません|れなかった|りにくい))/.test(n) ||
        /(聞き取(れない|れません|れなかった|りにくい))/.test(n) ||
        /(くりかえ(し|して|しください))/.test(n) ||
        /(繰り返(し|して|しください))/.test(n)
    );
}

function hasIntentKeyword(n) {
    return /(予約|よやく|変更|へんこう|かえる|変え|キャンセル|取り消し|とりけし|お問い合わせ|問い合わせ|といあわせ|質問|聞きたい|相談)/.test(n);
}

function isRepeat(n) {
    if (!hasRepeatMarker(n)) return false;
    if (hasIntentKeyword(n)) return false;
    return true;
}


// =============================================================
// 4. 番号判定 (Phase A)
// =============================================================
var SUFFIX = "(です|だ|でお?ねがい(します)?|でお願い(します)?|でいい(です)?|がいい(です)?|おねがい(します)?|お願い(します)?|になります|のほう|に|ね|よ)?";

function classifyByNumber(rawText, normText) {
    if (rawText === "1" || normText === "1") return "予約";
    if (rawText === "2" || normText === "2") return "変更";
    if (rawText === "3" || normText === "3") return "キャンセル";
    if (rawText === "4" || normText === "4") return "お問い合わせ";

    if (new RegExp("^(1|いち|イチ|一|ひとつ)" + SUFFIX + "$").test(normText)) return "予約";
    if (new RegExp("^(2|に|にい|にー|にぃ|二|ふたつ)" + SUFFIX + "$").test(normText)) return "変更";
    if (new RegExp("^(3|さん|さーん|さあん|三|みっつ)" + SUFFIX + "$").test(normText)) return "キャンセル";
    if (new RegExp("^(4|よん|よ|四|よっつ)" + SUFFIX + "$").test(normText)) return "お問い合わせ";

    var num1Re = /(^|[^0-9])(1ばん|いちばー?ん|一[番万判版晩])/;
    if (num1Re.test(normText)) return "予約";
    var num2Re = /(^|[^0-9])(2ばん|にばー?ん|二[番万判版晩位])/;
    if (num2Re.test(normText)) return "変更";
    var num3Re = /(^|[^0-9])(3ばん|さんばー?ん|三[番万判版晩])/;
    if (num3Re.test(normText)) return "キャンセル";
    var num4Re = /(^|[^0-9])(4ばん|よんばー?ん|四[番万判版晩])/;
    if (num4Re.test(normText)) return "お問い合わせ";
    return null;
}


// =============================================================
// 5. 内容判定 (Phase B) — スコアベース
// =============================================================
function classifyByVerbScore(n) {
    var candidates = [];
    // --- 予約 (STRONG) ---
    var score_予約 = 0;
    if (/予約/.test(n)) score_予約++;
    if (/よやく/.test(n)) score_予約++;
    if (score_予約 > 0) { candidates.push({label: "予約", score: score_予約, number: 1, strong: true}); }
    // --- 変更 (STRONG) ---
    var score_変更 = 0;
    if (/変更/.test(n)) score_変更++;
    if (/へんこう/.test(n)) score_変更++;
    if (/かえる/.test(n)) score_変更++;
    if (/変え/.test(n)) score_変更++;
    if (score_変更 > 0) { candidates.push({label: "変更", score: score_変更, number: 2, strong: true}); }
    // --- キャンセル (STRONG) ---
    var score_キャンセル = 0;
    if (/キャンセル/.test(n)) score_キャンセル++;
    if (/取り消し/.test(n)) score_キャンセル++;
    if (/とりけし/.test(n)) score_キャンセル++;
    if (score_キャンセル > 0) { candidates.push({label: "キャンセル", score: score_キャンセル, number: 3, strong: true}); }
    // --- お問い合わせ (WEAK) ---
    var score_お問い合わせ = 0;
    if (/お問い合わせ/.test(n)) score_お問い合わせ++;
    if (/問い合わせ/.test(n)) score_お問い合わせ++;
    if (/といあわせ/.test(n)) score_お問い合わせ++;
    if (/質問/.test(n)) score_お問い合わせ++;
    if (/聞きたい/.test(n)) score_お問い合わせ++;
    if (/相談/.test(n)) score_お問い合わせ++;
    if (score_お問い合わせ > 0) { candidates.push({label: "お問い合わせ", score: score_お問い合わせ, number: 4, strong: false}); }
    if (candidates.length === 0) return null;
    // 最高スコアを選択; 同スコアなら number が小さい方を優先
    candidates.sort(function(a, b) {
        if (b.score !== a.score) return b.score - a.score;
        return a.number - b.number;
    });
    return candidates[0].label;
}


// =============================================================
// 6. 統合 (reconcile)
// =============================================================
function isStrongVerbIntent(intent) {
    return intent === "予約"
        || intent === "変更"
        || intent === "キャンセル";
}

function reconcile(numIntent, verbIntent) {
    if (numIntent && verbIntent) {
        if (isStrongVerbIntent(verbIntent)) return verbIntent;
        return numIntent;
    }
    if (numIntent) return numIntent;
    if (verbIntent) return verbIntent;
    return "NO_RESULT";
}


// =============================================================
// 6.5 user_classification変換
// =============================================================
function toUserClassification(c) {
    if (c === "予約") return "予約";
    if (c === "変更") return "変更";
    if (c === "キャンセル") return "キャンセル";
    if (c === "お問い合わせ") return "お問い合わせ";
    return c;
}


// =============================================================
// 7. 判定パイプライン
// =============================================================
var normalized = normalize(text);

if (normalized.length === 0) {
    classification = "NO_RESULT";
} else if (isRepeat(normalized)) {
    classification = "REPEAT";
} else {
    var numIntent = classifyByNumber(text, normalized);
    var verbIntent = classifyByVerbScore(normalized);
    classification = reconcile(numIntent, verbIntent);
}


// =============================================================
// 8. 保存・出力
// =============================================================
if (classification !== "NO_RESULT" && classification !== "REPEAT") {
    var userClassification = toUserClassification(classification);

    var contextField = {
        contextName: "classification",
        displayType: "CLASSIFICATION",
        value: classification
    };
    try {
        $ivr.exec("save2db", "save", JSON.stringify({ contextField: contextField }));
    } catch (e) { /* silent */ }
    $runner.setObject("classification", classification);
    $runner.setObject("user_classification", userClassification);
}

$runner.setResult(classification);
